import java.util.ArrayList;

ArrayList<String> fruits = new ArrayList<>();
fruits.add("Apple");
fruits.add("Banana");
fruits.add("Cherry");
System.out.println(fruits);        // [Apple, Banana, Cherry]
System.out.println(fruits.size());  // 3
System.out.println(fruits.get(1));  // Banana

ArrayList<String> names = new ArrayList<>();
names.add("Alice"); names.add("Bob"); names.add("Charlie");

// 1. for-each (preferred)
for (String name : names) {
    System.out.println(name);
}

// 2. Traditional for (when you need index)
for (int i = 0; i < names.size(); i++) {
    System.out.println(i + ": " + names.get(i));
}

// 3. Iterator (safe removal)
Iterator<String> it = names.iterator();
while (it.hasNext()) {
    if (it.next().startsWith("B")) it.remove();
}

// WRONG: ArrayList<int> nums = new ArrayList<>();  // COMPILE ERROR

// RIGHT: Use wrapper class
ArrayList<Integer> nums = new ArrayList<>();
nums.add(10);    // autoboxing: int -> Integer
nums.add(20);
nums.add(30);
int first = nums.get(0);  // unboxing: Integer -> int
System.out.println(first + nums.get(1));  // 30

