import java.util.ArrayList;

public class Main {
    public static void main(String[] args) {
        ArrayList<String> stack = new ArrayList<>();

        // Push
        stack.add("Page 1");
        stack.add("Page 2");
        stack.add("Page 3");
        System.out.println("Stack: " + stack);

        // Peek (look at top)
        System.out.println("Top: " + stack.get(stack.size() - 1));

        // Pop (remove top)
        String popped = stack.remove(stack.size() - 1);
        System.out.println("Popped: " + popped);
        System.out.println("Stack: " + stack);

        // Pop again
        popped = stack.remove(stack.size() - 1);
        System.out.println("Popped: " + popped);
        System.out.println("Stack: " + stack);

        System.out.println("Empty: " + stack.isEmpty());
    }
}

import java.util.ArrayList;

public class Main {
    public static void main(String[] args) {
        ArrayList<Integer> nums = new ArrayList<>();
        for (int i = 1; i <= 10; i++) nums.add(i);
        System.out.println("Original: " + nums);

        // Filter: even numbers only
        ArrayList<Integer> evens = new ArrayList<>();
        for (int n : nums) {
            if (n % 2 == 0) evens.add(n);
        }
        System.out.println("Evens: " + evens);

        // Transform: square each number
        ArrayList<Integer> squares = new ArrayList<>();
        for (int n : nums) {
            squares.add(n * n);
        }
        System.out.println("Squares: " + squares);

        // Combine: sum of even squares
        int total = 0;
        for (int n : nums) {
            if (n % 2 == 0) total += n * n;
        }
        System.out.println("Sum of even squares: " + total);
    }
}

