import java.util.ArrayList;
import java.util.HashMap;
import java.util.Collections;
import java.util.Comparator;

class Student {
    String name;
    ArrayList<Integer> grades = new ArrayList<>();
    Student(String n) { name = n; }
    void addGrade(int g) { grades.add(g); }
    double average() {
        if (grades.isEmpty()) return 0;
        int sum = 0;
        for (int g : grades) sum += g;
        return (double) sum / grades.size();
    }
    String letterGrade() {
        double avg = average();
        if (avg >= 90) return "A";
        if (avg >= 80) return "B";
        if (avg >= 70) return "C";
        if (avg >= 60) return "D";
        return "F";
    }
    @Override public String toString() {
        return String.format("%s: %s avg=%.1f (%s)", name, grades, average(), letterGrade());
    }
}

public class Main {
    public static void main(String[] args) {
        ArrayList<Student> roster = new ArrayList<>();
        Student s1 = new Student("Alice"); s1.addGrade(92); s1.addGrade(88); s1.addGrade(95);
        Student s2 = new Student("Bob"); s2.addGrade(78); s2.addGrade(85); s2.addGrade(72);
        Student s3 = new Student("Charlie"); s3.addGrade(95); s3.addGrade(91); s3.addGrade(89);
        roster.add(s1); roster.add(s2); roster.add(s3);

        System.out.println("=== GRADEBOOK ===");
        for (Student s : roster) System.out.println(s);

        Collections.sort(roster, (a, b) -> Double.compare(b.average(), a.average()));
        System.out.println("\n=== RANKED ===");
        int rank = 1;
        for (Student s : roster) System.out.println(rank++ + ". " + s);

        System.out.printf("\nClass average: %.1f%n",
            roster.stream().mapToDouble(Student::average).average().orElse(0));
    }
}

